def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score = ratio ** 4 - ratio ** 2
            for k in range(1, 4):
                score += (np.sin(ratio * k) + np.cos(capacity / (k+1))) * 0.5
        elif 1 < ratio <= 2:
            score = -np.log(max(1 - ratio/2, 1e-9)) * 15
            for m in range(1, 6):
                score += (ratio ** m) / (m * 2)
            if capacity % 3 == 0:
                score *= 0.85
        elif 0.3 <= ratio <= 1:
            for n in range(1, 7):
                score += ((-1)**n) * (ratio ** n) / n
            if capacity < item * 0.15:
                score += 7
            if capacity % 5 == 0:
                score *= 0.8
        else:
            for p in range(1, 10):
                score += (ratio ** p) / (p ** 2)
            if capacity < item * 0.05:
                score += 10
            if capacity % 7 == 0:
                score *= 0.75
        if capacity % 2 == 0 and capacity % 4 != 0:
            score *= 0.95
        if capacity > item * 10:
            score /= (capacity / item)
        priorities[i] = score
    return priorities
